class MyCell(torch.nn.Module): def __init__(self): super(MyCell, self).__init__() self.linear = torch.nn.Linear(4, 4) def forward(self, x, h): new_h = torch.tanh(self.linear(x) + h) return new_h, new_h my_cell = MyCell() x, h = torch.rand(3, 4), torch.rand(3, 4) traced_cell = torch.jit.trace(my_cell, (x, h)) print(traced_cell) traced_cell(x, h) C++ api:
#include &lt;torch/script.h&gt; // One-stop header. #include &lt;iostream&gt; #include &lt;memory&gt; int main(int argc, const char* argv[]) { if (argc != 2) { std::cerr &lt;&lt; &#34;usage: example-app &lt;path-to-exported-script-module&gt;
&#34;; return -1; } torch::jit::script::Module module; try { // Deserialize the ScriptModule from a file using torch::jit::load(). module = torch::jit::load(argv[1]); } catch (const c10::Error&amp; e) { std::cerr &lt;&lt; &#34;error loading the model
&#34;; return -1; } std::cout &lt;&lt; &#34;ok
&#34;; }

